database.csstemplate:
.research-entry {
  border: 1px solid #ddd;
  padding: 15px;
  margin: 10px 0;
  border-radius: 5px;
}
.research-entry h3 {
  margin-top: 0;
  color: #0066cc;
  font-size: 1.2em;
}
.section-header {
  background-color: #f0f0f0;
  font-weight: bold;
  padding: 8px !important;
}
.research-actions {
  margin-top: 10px;
  text-align: right;
}
